#include <bits/stdc++.h>
using namespace std;
struct Race{
    int a,b;
}a[1000001];
bool cmp(Race a,Race b){
    if(a.b==b.b)return a.a<b.a;
    return a.b<b.b;
}
int n;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i].a>>a[i].b;
    sort(a+1,a+1+n,cmp);
    int x=a[1].b,cnt=1;
    for(int i=2;i<=n;i++){
        if(a[i].a>=x){cnt++;x=a[i].b;}
    }
    cout<<cnt;
    return 0;
}
